// ── OFFLINE LOOKUP ──────────────────────────────────────────
function offlineLookup(word) {
  word = word.toLowerCase().trim();
  return OFFLINE_DB[word] || null;
}

// Returns sorted list of all offline words
function offlineWordList() {
  return Object.keys(OFFLINE_DB).sort();
}

// Offline autocomplete
function offlineSuggest(prefix, limit) {
  limit = limit || 8;
  const p = prefix.toLowerCase();
  return Object.keys(OFFLINE_DB).filter(w => w.startsWith(p)).slice(0, limit);
}
